import React from 'react';
import Card from '../UI/Card';

const KpiCards = ({ data }) => {
  if (!data) return <div>Загрузка...</div>;

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
      <Card>
        <h3 className="text-gray-500 dark:text-gray-400 text-sm">Выручка</h3>
        <p className="text-2xl font-bold">{data.kpi.revenue.toLocaleString()} ₽</p>
      </Card>
      <Card>
        <h3 className="text-gray-500 dark:text-gray-400 text-sm">Заказы</h3>
        <p className="text-2xl font-bold">{data.kpi.orders}</p>
      </Card>
      <Card>
        <h3 className="text-gray-500 dark:text-gray-400 text-sm">Средний чек</h3>
        <p className="text-2xl font-bold">{data.kpi.avg_check} ₽</p>
      </Card>
      <Card>
        <h3 className="text-gray-500 dark:text-gray-400 text-sm">Возвраты</h3>
        <p className="text-2xl font-bold">{data.kpi.return_rate}%</p>
      </Card>
    </div>
  );
};

export default KpiCards;
